const ProcessFlowDiagram: React.FC = () => {
  const [zoom, setZoom] = useState(1);
  const [showLegend, setShowLegend] = useState(true);

  const handleZoomIn = () => setZoom(z => Math.min(z + 0.15, 3));
  const handleZoomOut = () => setZoom(z => Math.max(z - 0.15, 0.3));
  const handleReset = () => setZoom(1);

  return (
      <div style={{ display: "flex", gap: 16, height: "100%", fontFamily: "'Inter', 'Segoe UI', system-ui, sans-serif" }}>

        {/* ─── DIAGRAM CARD ─── */}
        <div style={{ flex: 1, background: "#161f2e", border: "1px solid rgba(255,255,255,0.08)", borderRadius: 12, overflow: "hidden", display: "flex", flexDirection: "column" }}>
          {/* Card header */}
          <div style={{ padding: "12px 16px", borderBottom: "1px solid rgba(255,255,255,0.07)", display: "flex", alignItems: "center", justifyContent: "space-between", flexShrink: 0 }}>
            <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
              <span style={{ width: 9, height: 9, borderRadius: "50%", background: "#f97316", display: "inline-block" }} />
              <span style={{ color: "#f97316", fontWeight: 700, fontSize: 14 }}>Принципиальная технологическая схема</span>
            </div>
            {/* Zoom controls */}
            <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
              <button
                  onClick={() => setShowLegend(l => !l)}
                  style={{
                    background: showLegend ? "rgba(59,122,222,0.2)" : "rgba(255,255,255,0.05)",
                    border: "1px solid rgba(255,255,255,0.1)",
                    color: "#94a3b8", borderRadius: 6, padding: "4px 10px",
                    cursor: "pointer", fontSize: 11,
                  }}
              >
                {showLegend ? "Скрыть" : "Показать"} обозначения
              </button>
              <div style={{ display: "flex", alignItems: "center", gap: 2, background: "rgba(255,255,255,0.05)", border: "1px solid rgba(255,255,255,0.09)", borderRadius: 6, padding: "3px 6px" }}>
                <button onClick={handleZoomOut} style={{ background: "none", border: "none", color: "#94a3b8", fontSize: 15, cursor: "pointer", lineHeight: 1, padding: "0 3px" }}>−</button>
                <span style={{ color: "#64748b", fontSize: 11, minWidth: 32, textAlign: "center" }}>{Math.round(zoom * 100)}%</span>
                <button onClick={handleZoomIn} style={{ background: "none", border: "none", color: "#94a3b8", fontSize: 15, cursor: "pointer", lineHeight: 1, padding: "0 3px" }}>+</button>
                <button onClick={handleReset} style={{ background: "none", border: "none", color: "#475569", fontSize: 10, cursor: "pointer", lineHeight: 1, padding: "0 2px" }}>↺</button>
              </div>
            </div>
          </div>
          {/* SVG area */}
          <div style={{ flex: 1, overflow: "auto", padding: 16, background: "#0d1117" }}>
            <div
                style={{ transform: `scale(${zoom})`, transformOrigin: "top left", width: "fit-content", transition: "transform 0.2s ease" }}
                dangerouslySetInnerHTML={{ __html: svgContent }}
            />
          </div>
        </div>

        {/* ─── RIGHT LEGEND PANEL ─── */}
        {showLegend && (
            <aside style={{ width: 220, display: "flex", flexDirection: "column", gap: 12, flexShrink: 0 }}>
              {/* Legend */}
              <div style={{ background: "#161f2e", border: "1px solid rgba(255,255,255,0.08)", borderRadius: 12, padding: 14 }}>
                <div style={{ display: "flex", alignItems: "center", gap: 7, marginBottom: 12 }}>
                  <span style={{ width: 8, height: 8, borderRadius: "50%", background: "#3b7ade", display: "inline-block" }} />
                  <span style={{ color: "#f1f5f9", fontWeight: 700, fontSize: 13 }}>Обозначения</span>
                </div>
                {legendItems.map(item => (
                    <div key={item.code} style={{ display: "flex", alignItems: "flex-start", gap: 8, padding: "5px 0", borderBottom: "1px solid rgba(255,255,255,0.05)" }}>
                      <span style={{ width: 10, height: 10, borderRadius: 2, background: item.color, flexShrink: 0, marginTop: 3 }} />
                      <div>
                        <div style={{ fontSize: 12, fontWeight: 600, color: "#e2e8f0" }}>{item.code}</div>
                        <div style={{ fontSize: 11, color: "#475569", marginTop: 1 }}>{item.name}</div>
                      </div>
                    </div>
                ))}
              </div>

              {/* Info */}
              <div style={{ background: "#161f2e", border: "1px solid rgba(255,255,255,0.08)", borderRadius: 12, padding: 14 }}>
                <div style={{ display: "flex", alignItems: "center", gap: 7, marginBottom: 10 }}>
                  <span style={{ fontSize: 13 }}>📋</span>
                  <span style={{ color: "#f1f5f9", fontWeight: 700, fontSize: 13 }}>О схеме</span>
                </div>
                <p style={{ margin: 0, fontSize: 11, color: "#475569", lineHeight: 1.6 }}>
                  <span style={{ color: "#94a3b8", fontWeight: 600 }}>Замедленное коксование</span> — термический крекинг тяжёлых остатков при 470–510 °C. Продукты: кокс, газ, бензин, газойли.
                </p>
                <div style={{ marginTop: 10, display: "flex", flexDirection: "column", gap: 5 }}>
                  {[
                    { dot: "#f97316", text: "Трубчатая печь — нагрев до 490–510 °C" },
                    { dot: "#3b7ade", text: "Коксовые камеры Р-1…Р-4 — d=7 м, h=30 м" },
                    { dot: "#22c55e", text: "Колонна К-1 — основная ректификация" },
                    { dot: "#a855f7", text: "К-4 — абсорбер, К-5 — стабилизация" },
                  ].map((row, i) => (
                      <div key={i} style={{ display: "flex", alignItems: "flex-start", gap: 7, fontSize: 11, color: "#475569" }}>
                        <span style={{ width: 7, height: 7, borderRadius: "50%", background: row.dot, flexShrink: 0, marginTop: 3 }} />
                        {row.text}
                      </div>
                  ))}
                </div>
              </div>
            </aside>
        )}
      </div>
  );
};

export default ProcessFlowDiagram;